  const chips=aiContext?[`What is ${aiContext.name}?`,"Is this right for me?","How does it work?","Any alternatives?"]:role==="patient"?["What is teeth whitening?","How do braces work?","Is this safe for kids?","Pain management tips"]:["Compare ceramic vs metal","APC™ bonding steps","Best adhesive for wet field","Clinpro™ for ortho"];
